THE RISK:
{
 "id": "colo-scope-geography-misallocation",
 "title": "Apportioning all-segment TAM by colocation MW plants 29% of the market in the wrong countries — and the Year-1 channel plan inherits the error",
 "narrative": "The geo split apportions the entire TAM — including the 29% enterprise on-premise segment — by colocation MW. But enterprise PDU demand follows installed IT load, not colo halls, and the two geographies diverge sharply in CE: Germany's installed load (BMWK >2,700MW) dwarfs its colo figure (1,737MW), Switzerland is famously self-operation-heavy (850MW installed vs 274MW colo), while the Netherlands is the mirror image — an Amsterdam colo hub with a thin enterprise base. The ledger's own cross-checks show exactly this (DE 0.50 colo vs 0.42 installed; CH 0.08 vs 0.13) and then average past it. For a venture whose first-year channel is 'large operators' concentrated in Frankfurt and Amsterdam, the model quietly relocates a third of the TAM into the two metros it happens to be targeting — flattering the reachable share while the real enterprise demand sits in Swiss banks, Austrian utilities, and Polish industrials the channel never touches.",
 "category": "model-structure",
 "targetNodes": [
  "geo.DE",
  "geo.NL",
  "geo.CH",
  "geo.PL"
 ],
 "mechanism": [
  {
   "step": "trigger",
   "text": "The geo dimension uses a single colo-MW apportionment for all segments, but 29% of the TAM is enterprise on-premise whose geography follows installed load — and EUDCA confirms roughly one-third of Europe's IT power is outside commercial colo/hyperscale",
   "refs": [
    "ledger:seg.enterprise",
    "digest:geo-region-denominator#c9",
    "ledger:geo.DE"
   ]
  },
  {
   "step": "propagation",
   "text": "Where colo and installed scopes diverge, the ledger's own cross-checks disagree systematically: DE 0.50 (colo) vs 0.42 (BMWK installed), CH 0.08 vs 0.13 (self-operated-inclusive), PL 0.07 vs 0.10 (Mordor installed) — the colo lens over-weights the Amsterdam/Frankfurt hub countries and under-weights self-operation-heavy markets",
   "refs": [
    "ledger:geo.DE",
    "ledger:geo.CH",
    "ledger:geo.PL",
    "ledger:geo.NL"
   ]
  },
  {
   "step": "model-impact",
   "text": "Blending the enterprise 29% on an installed-load geography shifts the mix out of NL and DE toward CH and PL; the venture's operator-first channel (Frankfurt/Amsterdam colo) then covers a smaller true share of the TAM than the current split implies, compressing the reachable slice behind serviceableFactor",
   "refs": [
    "profile:Who is the primary buyer you'll sell through first?",
    "ledger:serviceableFactor",
    "ledger:cust.operator-large"
   ]
  }
 ],
 "whyMissable": "Every geo node individually documents its colo-vs-installed cross-check and brackets it in the band — the divergence looks handled. What no band captures is the correlation: all four scope errors point the same way at once (toward the colo hubs), and they interact with a segment split and a channel choice that live on different ledger dimensions. Node-by-node review cannot see a cross-dimensional misallocation.",
 "expectedObviousness": "low",
 "falsifier": "A vendor country-revenue split (Omdia country tables or a Schneider/Vertiv CE distributor sell-through report) showing rack-PDU sales proportional to colocation MW rather than installed IT load.",
 "likelihood": {
  "value": 0.45,
  "rationale": "The scope divergences are documented in the ledger's own cross-checks for four of seven countries and all point the same direction; the open question is only how tightly enterprise PDU refresh demand tracks installed load, which is unmeasured. [evidence revision: The scope-divergence premises (DE >2,700 MW installed vs ~1,737 MW colo; CH 850 MW installed vs ~274 MW colo) are now confirmed by multiple independent authoritative sources, strengthening the mechanism's foundation. However, the decisive falsifier — a vendor country-revenue split establishing whether enterprise PDU demand actually tracks installed load vs colo MW — remains unmeasured, so the remaining uncertainty caps the upward revision. A modest increase from 0.40 to 0.45 reflects the confirmed geographic divergence while preserving the open empirical question about demand tracking.]",
  "basis": "evidence",
  "revisedFrom": 0.4
 },
 "perturbation": [
  {
   "nodeId": "geo.DE",
   "op": "set",
   "value": 0.46,
   "note": "Blend colo-weighted 71% of TAM with installed-load-weighted 29% enterprise slice"
  },
  {
   "nodeId": "geo.NL",
   "op": "set",
   "value": 0.24,
   "note": "NL enterprise base thin relative to its Amsterdam colo weight"
  },
  {
   "nodeId": "geo.CH",
   "op": "set",
   "value": 0.11,
   "note": "Self-operation-heavy Switzerland gains weight under installed-load blending"
  },
  {
   "nodeId": "geo.PL",
   "op": "set",
   "value": 0.09,
   "note": "Poland installed load (660MW Mordor) vs colo 228MW pulls share up"
  }
 ],
 "indicators": [
  {
   "signal": "Share of CE rack-PDU demand originating from enterprise/self-operated sites vs colo fit-outs",
   "where": "BMWK annual 'German data centre landscape' update (installed vs colo split); CBRE Suisse commercial-vs-self-operated capacity report",
   "threshold": "Enterprise/self-operated share of national capacity holding >35% in DE/CH",
   "updates": "increases"
  },
  {
   "signal": "Where early inbound demand actually comes from during launch",
   "where": "Venture's own CRM geography vs the model's geo weights; distributor sell-through reports from CE master distributors",
   "threshold": "≥30% of qualified pipeline from outside DE+NL within 6 months",
   "updates": "increases"
  }
 ],
 "mitigations": [
  {
   "action": "Split the geo apportionment by segment: colo MW for hyperscale/colo slices, installed IT load for the enterprise slice, and recompute the funnel",
   "type": "information",
   "voiNodeId": "geo.DE",
   "note": "Pure re-derivation from data already in the ledger's cross-checks — near-zero cost"
  },
  {
   "action": "Add a Swiss/Austrian enterprise reseller to the Year-1 channel plan rather than relying solely on Frankfurt/Amsterdam operator relationships",
   "type": "strategic",
   "voiNodeId": null,
   "note": "Hedges the channel against the geography the colo lens hides"
  }
 ],
 "evidenceStatus": "corroborated",
 "evidence": [
